ht="350" style="border:0;display:block;" allowfullscreen="" loading="lazy"            referrerpolicy="no-referrer-when-downgrade"></iframe>        </div>      </div>    </div>  </div>  @include('layout.footer')  <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js" defer></script>  <script>  (function() {    var canvas = document.getElementById('threeCanvas');    if (!canvas) return;    var scene = new THREE.Scene();    var camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);    var renderer = new THREE.WebGLRenderer({      canvas: canvas,      alpha: true,      antialias: true    });    renderer.setSize(window.innerWidth, window.innerHeight);    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));    // Particles    var particleCount = 200;    var positions = new Float32Array(particleCount * 3);    for (var i = 0; i < particleCount; i++) {      positions[i * 3] = (Math.random() - 0.5) * 30;      positions[i * 3 + 1] = (Math.random() - 0.5) * 30;      positions[i * 3 + 2] = (Math.random() - 0.5) * 15 - 5;    }    var pGeom = new THREE.BufferGeometry();    pGeom.setAttribute('position', new THREE.BufferAttribute(positions, 3));    var pMat = new THREE.PointsMaterial({      color: 0x22c55e,      size: 0.03,      transparent: true,      opacity: 0.4,      blending: THREE.AdditiveBlending    });    var particles = new THREE.Points(pGeom, pMat);    scene.add(particles);    // Load image textures and create floating planes    var loader = new THREE.TextureLoader();    var baseUrl = "{{ asset('frontend/assets/images') }}";    var planes = [];    function createImagePlane(imgSrc, x, y, z, scale) {      loader.load(imgSrc, function(texture) {        var aspect = texture.image.width / texture.image.height;        var geom = new THREE.PlaneGeometry(scale * aspect, scale);        var mat = new THREE.MeshBasicMaterial({          map: texture,          transparent: true,          depthWrite: false,          side: THREE.DoubleSide,        });        var mesh = new THREE.Mesh(geom, mat);        mesh.position.set(x, y, z);        mesh.userData = {          floatSpeed: 0.003 + Math.random() * 0.002,          floatPhase: Math.random() * Math.PI * 2,          rotSpeedY: (Math.random() - 0.5) * 0.004,          rotSpeedX: (Math.random() - 0.5) * 0.002,          baseY: y,        };        scene.add(mesh);        planes.push(mesh);        // Glow ring behind        var ringGeom = new THREE.RingGeometry(scale * aspect * 0.45, scale * aspect * 0.55, 32);        var ringMat = new THREE.MeshBasicMaterial({          color: 0x22c55e,          transparent: true,          opacity: 0.08,          side: THREE.DoubleSide,          depthWrite: false,        });        var ring = new THREE.Mesh(ringGeom, ringMat);        ring.position.set(x, y, z - 0.05);        ring.userData = {          parentMesh: mesh        };        scene.add(ring);        planes.push(ring);      });    }    createImagePlane(baseUrl + '/laptop.png', -2.5, 0.5, -1, 2.0);    createImagePlane(baseUrl + '/world.png', 2.8, -0.8, -1.5, 1.8);    // Grid floor (subtle)    var gridHelper = new THREE.GridHelper(12, 24, 0x22c55e, 0x22c55e);    gridHelper.position.y = -3.5;    gridHelper.material.transparent = true;    gridHelper.material.opacity = 0.06;    scene.add(gridHelper);    camera.position.z = 5.5;    camera.position.y = 0.3;    var mouseX = 0,      mouseY = 0;    document.addEventListener('mousemove', function(e) {      mouseX = (e.clientX / window.innerWidth) * 2 - 1;      mouseY = -(e.clientY / window.innerHeight) * 2 + 1;    });    var time = 0;    function animate() {      requestAnimationFrame(animate);      time += 0.005;      particles.rotation.y += 0.0005;      planes.forEach(function(mesh) {        if (mesh.userData.parentMesh) return;        mesh.position.y = mesh.userData.baseY + Math.sin(time * 5 + mesh.userData.floatPhase) * 0.15;        mesh.rotation.y += mesh.userData.rotSpeedY;        mesh.rotation.x += mesh.userData.rotSpeedX;      });      camera.position.x += (mouseX * 0.4 - camera.position.x) * 0.02;      camera.position.y += (-mouseY * 0.3 + 0.3 - camera.position.y) * 0.02;      camera.lookAt(scene.position);      renderer.render(scene, camera);    }    animate();    window.addEventListener('resize', function() {      camera.aspect = window.innerWidth / window.innerHeight;      camera.updateProjectionMatrix();      renderer.setSize(window.innerWidth, window.innerHeight);    });  })();  </script>  @if (session('success'))  <script>  Swal.fire({    icon: 'success',    title: 'Thank you!',    text: '{{ session('    success ') }}',    confirmButtonColor: '#22c55e',    background: '#1e293b',    color: '#fff'  })  </script>  @endif  @if ($errors->any())  <script>  Swal.fire({    icon: 'error',    title: 'Oops...',    html: `{!! implode('<br>', $errors->all()) !!}`,    confirmButtonColor: '#d33',    background: '#1e293b',    color: '#fff'  })  </script>  @endif</body></html>
